mapper.update:
update se_process_rollback_record

    gmt_modified = CURRENT_TIMESTAMP
    ,rollback_reason = #{rollbackReason}

where id = #{id}
 and tenant_id = #{tenantId}

mapper.select:
select 
from se_process_rollback_record
where id = #{id}
 and tenant_id = #{tenantId}

select 
from se_process_rollback_record
where process_instance_id = #{processInstanceId}
 and tenant_id = #{tenantId} 
order by gmt_create desc

mapper.delete:
delete from se_process_rollback_record
where id = #{id}
 and tenant_id = #{tenantId}
